protected static function parseNumericTimezone(string|int|float $timezone): string
    {
        if (abs((float) $timezone) > static::MAXIMUM_TIMEZONE_OFFSET) {
            throw new InvalidTimeZoneException(
                'Absolute timezone offset cannot be greater than '.
                static::MAXIMUM_TIMEZONE_OFFSET.'.',
            );
        }

        return ($timezone >= 0 ? '+' : '').ltrim((string) $timezone, '+').':00';
    }

protected static function getDateTimeZoneNameFromMixed(string|int|float $timezone): string
    {
        if (\is_string($timezone)) {
            $timezone = preg_replace('/^\s*([+-]\d+)(\d{2})\s*$/', '$1:$2', $timezone);
        }

        if (is_numeric($timezone)) {
            return static::parseNumericTimezone($timezone);
        }

        return $timezone;
    }

private function moveUninstallsToFront(array $operations): array
    {
        $uninstOps = [];
        foreach ($operations as $idx => $op) {
            if ($op instanceof Operation\UninstallOperation || $op instanceof Operation\MarkAliasUninstalledOperation) {
                $uninstOps[] = $op;
                unset($operations[$idx]);
            }
        }

        return array_merge($uninstOps, $operations);
    }

public function __construct(
    string $source,
    string $target,
    ConstraintInterface $constraint,
    $description = self::TYPE_UNKNOWN,
    ?string $prettyConstraint = null
) {
    $this->source = strtolower($source);
    $this->target = strtolower($target);
    $this->constraint = $constraint;
    $this->description = self::TYPE_DEV_REQUIRE === $description ? 'requires (for development)' : $description;
    $this->prettyConstraint = $prettyConstraint;
}

public static function sortPackagesAlphabetically(array $packages): array
    {
        usort($packages, static function (PackageInterface $a, PackageInterface $b) {
            return $a->getName() <=> $b->getName();
        });

        return $packages;
    }

public function setParameter(string|int $key, mixed $value, ParameterType|ArrayParameterType|string|int|null $type = null): static
    {
        $existingParameter = $this->getParameter($key);

        if ($existingParameter !== null) {
            $existingParameter->setValue($value, $type);

            return $this;
        }

        $this->parameters->add(new Parameter($key, $value, $type));

        return $this;
    }

public function createNamedParameter(mixed $value, ParameterType|ArrayParameterType|string|int|null $type = null, string|null $placeholder = null): string
    {
        if ($placeholder === null) {
            $this->boundCounter++;
            $placeholder = ':dcValue' . $this->boundCounter;
        }

        $this->setParameter(substr($placeholder, 1), $value, $type);

        return $placeholder;
    }

private function addInheritedFields(ClassMetadata $subClass, ClassMetadata $parentClass): void
    {
        foreach ($parentClass->fieldMappings as $mapping) {
            $subClassMapping = clone $mapping;
            $this->addMappingInheritanceInformation($subClassMapping, $parentClass);
            $subClass->addInheritedFieldMapping($subClassMapping);
        }

        foreach ($parentClass->propertyAccessors as $name => $field) {
            $subClass->propertyAccessors[$name] = $field;
        }
    }

protected function assignDefaultVersionAndUpsertableValues(object $entity, array $id): void
    {
        $values = $this->fetchVersionAndNotUpsertableValues($this->class, $id);

        foreach ($values as $field => $value) {
            $value = Type::getType($this->class->fieldMappings[$field]->type)->convertToPHPValue($value, $this->platform);

            $this->class->setFieldValue($entity, $field, $value);
        }
    }

private function computeScheduleInsertsChangeSets(): void
    {
        foreach ($this->entityInsertions as $entity) {
            $class = $this->em->getClassMetadata($entity::class);

            $this->computeChangeSet($class, $entity);
        }
    }

private function inheritIdGeneratorMapping(ClassMetadata $class, ClassMetadata $parent): void
    {
        if ($parent->isIdGeneratorSequence()) {
            $class->setSequenceGeneratorDefinition($parent->sequenceGeneratorDefinition);
        }

        if ($parent->generatorType) {
            $class->setIdGeneratorType($parent->generatorType);
        }

        if ($parent->idGenerator ?? null) {
            $class->setIdGenerator($parent->idGenerator);
        }
    }

public function sendAsync(RequestInterface $request, array $options = []): PromiseInterface
    {
        // Merge the base URI into the request URI if needed.
        $options = $this->prepareDefaults($options);

        return $this->transfer(
            $request->withUri($this->buildUri($request->getUri(), $options), $request->hasHeader('Host')),
            $options
        );
    }

public function __invoke(RequestInterface $request, array $options): PromiseInterface
    {
        if (!isset($options['retries'])) {
            $options['retries'] = 0;
        }

        $fn = $this->nextHandler;

        return $fn($request, $options)
            ->then(
                $this->onFulfilled($request, $options),
                $this->onRejected($request, $options)
            );
    }

private static function getLastHeaderBlock(array $headers): array
    {
        $lastStatusLine = 0;

        foreach ($headers as $index => $line) {
            if (\preg_match('/^HTTP\/\S+\s+/i', $line)) {
                $lastStatusLine = $index;
            }
        }

        return \array_slice($headers, $lastStatusLine);
    }

public static function headersFromLines(iterable $lines): array
    {
        $headers = [];

        foreach ($lines as $line) {
            $parts = \explode(':', $line, 2);
            $headers[\trim($parts[0])][] = isset($parts[1]) ? \trim($parts[1]) : null;
        }

        return $headers;
    }

public static function fromString(string $version): self {
    if (!preg_match('/^(\d+)\.(\d+)/', $version, $matches)) {
        throw new \LogicException("Invalid PHP version \"$version\"");
    }
    return self::fromComponents((int) $matches[1], (int) $matches[2]);
}

private function evaluateConstFetch(Expr\ConstFetch $expr) {
    $name = $expr->name->toLowerString();
    switch ($name) {
        case 'null': return null;
        case 'false': return false;
        case 'true': return true;
    }

    return ($this->fallbackEvaluator)($expr);
}

public static function normalizeNode($node): Node {
    if ($node instanceof Builder) {
        return $node->getNode();
    }

    if ($node instanceof Node) {
        return $node;
    }

    throw new \LogicException('Expected node or builder object');
}

public static function normalizeStmt($node): Stmt {
    $node = self::normalizeNode($node);
    if ($node instanceof Stmt) {
        return $node;
    }

    if ($node instanceof Expr) {
        return new Stmt\Expression($node);
    }

    throw new \LogicException('Expected statement or expression node');
}

protected function parseNumString(string $str, array $attributes) {
    if (!preg_match('/^(?:0|-?[1-9][0-9]*)$/', $str)) {
        return new String_($str, $attributes);
    }

    $num = +$str;
    if (!is_int($num)) {
        return new String_($str, $attributes);
    }

    return new Int_($num, $attributes);
}

public function getShortName(string $name, int $type): Name {
    $possibleNames = $this->getPossibleNames($name, $type);

    // Find shortest name
    $shortestName = null;
    $shortestLength = \INF;
    foreach ($possibleNames as $possibleName) {
        $length = strlen($possibleName->toCodeString());
        if ($length < $shortestLength) {
            $shortestName = $possibleName;
            $shortestLength = $length;
        }
    }

    return $shortestName;
}

protected function handleBuiltinTypes(Name $name) {
    if (!$name->isUnqualified()) {
        return $name;
    }

    $lowerName = $name->toLowerString();
    if (!$this->phpVersion->supportsBuiltinType($lowerName)) {
        return $name;
    }

    return new Node\Identifier($lowerName, $name->getAttributes());
}

private function addAlias(Node\UseItem $use, int $type, ?Name $prefix = null): void {
    // Add prefix for group uses
    $name = $prefix ? Name::concat($prefix, $use->name) : $use->name;
    // Type is determined either by individual element or whole use declaration
    $type |= $use->type;

    $this->nameContext->addAlias(
        $name, (string) $use->getAlias(), $type, $use->getAttributes()
    );
}

private function resolveType(?Node $node): ?Node {
    if ($node instanceof Name) {
        return $this->resolveClassName($node);
    }
    if ($node instanceof Node\NullableType) {
        $node->type = $this->resolveType($node->type);
        return $node;
    }
    if ($node instanceof Node\UnionType || $node instanceof Node\IntersectionType) {
        foreach ($node->types as &$type) {
            $type = $this->resolveType($type);
        }
        return $node;
    }
    return $node;
}

private function getSmtpErrorMessage($base_key)
    {
        $message = self::lang($base_key);
        $error = $this->smtp->getError();
        if (!empty($error['error'])) {
            $message .= ' ' . $error['error'];
            if (!empty($error['detail'])) {
                $message .= ' ' . $error['detail'];
            }
        }

        return $message;
    }

public function reset(): void
    {
        foreach ($this->handlers as $handler) {
            if ($handler instanceof ResettableInterface) {
                $handler->reset();
            }
        }

        foreach ($this->processors as $processor) {
            if ($processor instanceof ResettableInterface) {
                $processor->reset();
            }
        }
    }

protected function callListeners(iterable $listeners, string $eventName, object $event): void
    {
        $stoppable = $event instanceof StoppableEventInterface;

        foreach ($listeners as $listener) {
            if ($stoppable && $event->isPropagationStopped()) {
                break;
            }
            $listener($event, $eventName, $this);
        }
    }

private function deduplicateDefaultBranchAlias(BasePackage $package): BasePackage
    {
        if ($package instanceof AliasPackage && $package->getPrettyVersion() === VersionParser::DEFAULT_BRANCH_ALIAS) {
            $package = $package->getAliasOf();
        }

        return $package;
    }

private function guardMax(RequestInterface $request, ResponseInterface $response, array &$options): void
    {
        $current = $options['__redirect_count']
            ?? 0;
        $options['__redirect_count'] = $current + 1;
        $max = $options['allow_redirects']['max'];

        if ($options['__redirect_count'] > $max) {
            throw new TooManyRedirectsException("Will not follow more than {$max} redirects", $request, $response);
        }
    }

private function normalizeConstName(string $name): string {
    $nsSep = strrpos($name, '\\');
    if (false === $nsSep) {
        return $name;
    }

    // Constants have case-insensitive namespace and case-sensitive short-name
    $ns = substr($name, 0, $nsSep);
    $shortName = substr($name, $nsSep + 1);
    return strtolower($ns) . '\\' . $shortName;
}
